# Internal mechanics: gradient checkpointing and selective layer unfreezing
import torch
import torch.nn as nn
from torch.utils.checkpoint import checkpoint

class CricketBattingModel(nn.Module):
    def __init__(self, vocab_size=5000, hidden_dim=768, num_layers=12):
        super().__init__()
        self.embedding = nn.Embedding(vocab_size, hidden_dim)
        self.transformer_layers = nn.ModuleList([
            nn.TransformerEncoderLayer(hidden_dim, nhead=8, batch_first=True)
            for _ in range(num_layers)
        ])
        self.classifier = nn.Linear(hidden_dim, 3)  # shot_type prediction

    def forward(self, batting_sequence, use_checkpointing=True):
        x = self.embedding(batting_sequence)
        # Pre-trained layers: frozen
        for layer in self.transformer_layers[:10]:
            x = layer(x)
        # Fine-tuned layers: active backprop
        for layer in self.transformer_layers[10:]:
            if use_checkpointing:
                x = checkpoint(layer, x, use_reentrant=False)
            else:
                x = layer(x)
        logits = self.classifier(x[:, 0])  # CLS token
        return logits

# Selective unfreezing strategy
model = CricketBattingModel()

# Freeze pre-training layers (Rohit's core technique)
for param in model.embedding.parameters():
    param.requires_grad = False
for layer in model.transformer_layers[:10]:
    for param in layer.parameters():
        param.requires_grad = False

# Unfreeze fine-tuning layers and head (adaptation phase)
for layer in model.transformer_layers[10:]:
    for param in layer.parameters():
        param.requires_grad = True
for param in model.classifier.parameters():
    param.requires_grad = True

optimizer = torch.optim.AdamW(
    filter(lambda p: p.requires_grad, model.parameters()),
    lr=1e-4  # Lower LR for fine-tuning
)

print(f"Trainable parameters: {sum(p.numel() for p in model.parameters() if p.requires_grad)}")
